// // This module performs a barrel shift operation on the input data. It supports both left and right shifts based on the shift_left signal. The shift amount is specified by the shift_amount input.
module barrel_shifter(
    input [31:0] data_in,
    input [4:0] shift_amount,
    input shift_left,
    output [31:0] data_out
    );

    assign data_out = shift_left ? (data_in << shift_amount) : (data_in >> shift_amount);
endmodule
